import React from "react";
import ReactECharts from "echarts-for-react";

const Dashboard = () => {
  // Initialize chart

  const lineRaceOptions = {
    title: { text: "Line Race Chart" },
    tooltip: { trigger: "axis" },
    legend: { data: ["Category A", "Category B", "Category C"] },
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: { type: "value" },
    series: [
      {
        name: "Category A",
        type: "line",
        data: [10, 20, 30, 40, 50, 60, 70],
        smooth: true,
        animationDurationUpdate: 1000, // Smooth transition
      },
      {
        name: "Category B",
        type: "line",
        data: [15, 25, 35, 45, 55, 65, 75],
        smooth: true,
        animationDurationUpdate: 1000,
      },
      {
        name: "Category C",
        type: "line",
        data: [5, 15, 25, 35, 45, 55, 65],
        smooth: true,
        animationDurationUpdate: 1000,
      },
    ],
  };

  // Set initial chart options
  chart.setOption(lineRaceOptions);

  // Simulate data updates for the line race animation
  let index = 0;
  const updateInterval = setInterval(() => {
    if (index >= 20) {
      clearInterval(updateInterval); // Stop animation after a few updates
      return;
    }

    // Generate new random data
    lineRaceOptions.series.forEach((series) => {
      series.data = series.data.map(
        (val) => val + Math.round(Math.random() * 10 - 5)
      ); // Slight variation
    });

    // Apply updated data with smooth animation
    chart.setOption({
      series: lineRaceOptions.series,
    });

    index++;
  }, 1000); // Update every second

  const chartOptions = {
    title: {
      text: "Sales Over Time",
    },
    tooltip: {},
    legend: {
      data: ["Sales Line", "Sales Bar"],
    },
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: [
      {
        type: "value",
        name: "Sales",
      },
      {
        type: "value",
        name: "Other Metric",
        position: "right",
        offset: 0,
      },
    ],
    series: [
      {
        name: "Sales Line",
        type: "line",
        data: [30, 40, 35, 50, 49, 60, 70],
      },
      {
        name: "Sales Bar",
        type: "bar",
        data: [20, 30, 25, 40, 35, 50, 60],
        yAxisIndex: 1,
      },
    ],
  };

  const barChartOptions = {
    title: {
      text: "Sales by Month",
    },
    tooltip: {},
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: {
      type: "value",
    },
    series: [
      {
        name: "Sales",
        type: "bar",
        data: [20, 30, 25, 40, 35, 50, 60],
      },
    ],
  };

  const pieChartOptions = {
    title: {
      text: "Inspection Types",
    },
    tooltip: {},
    series: [
      {
        name: "Types",
        type: "pie",
        data: [
          { value: 30, name: "Inspections" },
          { value: 40, name: "Follow-ups" },
          { value: 30, name: "Re-inspections" },
        ],
      },
    ],
  };

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="kpis">
        <div className="kpi">
          <h2>Total Sales</h2>
          <p>$100,000</p>
        </div>
        <div className="kpi">
          <h2>Total Inspections</h2>
          <p>250</p>
        </div>
        <div className="kpi">
          <h2>Active Users</h2>
          <p>150</p>
        </div>
      </div>
      <ReactECharts option={lineRaceOptions} />
      <ReactECharts option={chartOptions} />
      <ReactECharts option={barChartOptions} />
      <ReactECharts option={pieChartOptions} />
    </div>
  );
};

export default Dashboard;
